# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

package com.example.biometricauth

import android.content.Context
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.LinearLayout
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    companion object {
        private const val PREFS_NAME = "biometric_auth_prefs"
        private const val KEY_AUTHENTICATED = "is_authenticated"
        private const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
        private const val KEY_USERNAME = "stored_username"
        private const val KEY_PASSWORD = "stored_password"
        private const val DEFAULT_USERNAME = "admin"
        private const val DEFAULT_PASSWORD = "password123"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        // Store default credentials if not already stored
        if (!sharedPreferences.contains(KEY_USERNAME)) {
            sharedPreferences.edit()
                .putString(KEY_USERNAME, DEFAULT_USERNAME)
                .putString(KEY_PASSWORD, DEFAULT_PASSWORD)
                .apply()
        }

        // Check if user is already authenticated via biometric
        if (isAuthenticated() && isBiometricEnabled()) {
            showHomeScreen()
            return
        }

        // Check if biometric is available and enabled
        if (isBiometricAvailable() && isBiometricEnabled()) {
            setupBiometricPrompt()
            showBiometricPrompt()
        } else {
            showLoginScreen()
        }
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)
    }

    private fun isBiometricEnabled(): Boolean {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false)
    }

    private fun setAuthenticated(authenticated: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, authenticated).apply()
    }

    private fun setBiometricEnabled(enabled: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_BIOMETRIC_ENABLED, enabled).apply()
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> true
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                showToast("No biometric hardware available")
                false
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                showToast("Biometric hardware unavailable")
                false
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                showToast("No biometric credentials enrolled. Please set up fingerprint in device settings.")
                false
            }
            else -> false
        }
    }

    private fun setupBiometricPrompt() {
        executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                            // User clicked "Use Password" button
                            showLoginScreen()
                        }
                        BiometricPrompt.ERROR_USER_CANCELED -> {
                            showToast("Authentication cancelled")
                            showLoginScreen()
                        }
                        BiometricPrompt.ERROR_LOCKOUT -> {
                            showToast("Too many attempts. Please use password.")
                            showLoginScreen()
                        }
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                            showToast("Biometric permanently locked. Please use password.")
                            showLoginScreen()
                        }
                        else -> {
                            showToast("Authentication error: $errString")
                            showLoginScreen()
                        }
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    showToast("Authentication successful!")
                    setAuthenticated(true)
                    showHomeScreen()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    showToast("Authentication failed. Try again.")
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Use your fingerprint to log in")
            .setDescription("Place your finger on the sensor to verify your identity")
            .setNegativeButtonText("Use Password")
            .setConfirmationRequired(false)
            .build()
    }

    private fun showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun showLoginScreen() {
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
        }

        val titleText = TextView(this).apply {
            text = "Welcome Back"
            textSize = 28f
            setTextColor(resources.getColor(android.R.color.black, theme))
            setPadding(0, 0, 0, 16)
        }

        val subtitleText = TextView(this).apply {
            text = "Please sign in to continue"
            textSize = 16f
            setTextColor(resources.getColor(android.R.color.darker_gray, theme))
            setPadding(0, 0, 0, 48)
        }

        val usernameInput = EditText(this).apply {
            hint = "Username"
            setPadding(32, 32, 32, 32)
            textSize = 16f
            setSingleLine(true)
        }

        val passwordInput = EditText(this).apply {
            hint = "Password"
            setPadding(32, 32, 32, 32)
            textSize = 16f
            setSingleLine(true)
            inputType = android.text.InputType.TYPE_CLASS_TEXT or android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD
        }

        val loginButton = Button(this).apply {
            text = "Login"
            textSize = 16f
            setPadding(32, 24, 32, 24)
            setOnClickListener {
                val username = usernameInput.text.toString().trim()
                val password = passwordInput.text.toString().trim()
                handlePasswordLogin(username, password)
            }
        }

        val biometricButton = Button(this).apply {
            text = "Use Fingerprint Instead"
            textSize = 14f
            setPadding(32, 24, 32, 24)
            setOnClickListener {
                if (isBiometricAvailable()) {
                    setupBiometricPrompt()
                    showBiometricPrompt()
                } else {
                    showToast("Biometric authentication not available")
                }
            }
        }

        val spacer = { height: Int ->
            android.view.View(this).apply {
                layoutParams = LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT, height
                )
            }
        }

        layout.addView(titleText)
        layout.addView(subtitleText)
        layout.addView(usernameInput)
        layout.addView(spacer(24))
        layout.addView(passwordInput)
        layout.addView(spacer(48))
        layout.addView(loginButton)
        layout.addView(spacer(24))

        if (isBiometricAvailable()) {
            layout.addView(biometricButton)
        }

        setContentView(layout)
    }

    private fun handlePasswordLogin(username: String, password: String) {
        if (username.isEmpty() || password.isEmpty()) {
            showToast("Please enter both username and password")
            return
        }

        val storedUsername = sharedPreferences.getString(KEY_USERNAME, DEFAULT_USERNAME)
        val storedPassword = sharedPreferences.getString(KEY_PASSWORD, DEFAULT_PASSWORD)

        if (username == storedUsername && password == storedPassword) {
            showToast("Login successful!")
            setAuthenticated(true)

            // Offer to enable biometric for next time
            if (isBiometricAvailable() && !isBiometricEnabled()) {
                showEnableBiometricDialog()
            } else {
                showHomeScreen()
            }
        } else {
            showToast("Invalid username or password")
        }
    }

    private fun showEnableBiometricDialog() {
        val builder = android.app.AlertDialog.Builder(this)
        builder.setTitle("Enable Biometric Login")
        builder.setMessage("Would you like to enable fingerprint authentication for faster login next time?")
        builder.setPositiveButton("Yes") { dialog, _ ->
            setBiometricEnabled(true)
            showToast("Biometric login enabled!")
            dialog.dismiss()
            showHomeScreen()
        }
        builder.setNegativeButton("Not Now") { dialog, _ ->
            dialog.dismiss()
            showHomeScreen()
        }
        builder.setCancelable(false)
        builder.show()
    }

    private fun showHomeScreen() {
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
            gravity = android.view.Gravity.CENTER
        }

        val welcomeText = TextView(this).apply {
            text = "🏠 Home Screen"
            textSize = 32f
            setTextColor(resources.getColor(android.R.color.black, theme))
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 24)
        }

        val statusText = TextView(this).apply {
            text = "You are successfully authenticated!"
            textSize = 18f
            setTextColor(resources.getColor(android.R.color.holo_green_dark, theme))
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 16)
        }

        val biometricStatusText = TextView(this).apply {
            val biometricStatus = if (isBiometricEnabled()) "Enabled ✅" else "Disabled ❌"
            text = "Biometric Login: $biometricStatus"
            textSize = 14f
            setTextColor(resources.getColor(android.R.color.darker_gray, theme))
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 48)
        }

        val toggleBiometricButton = Button(this).apply {
            text = if (isBiometricEnabled()) "Disable Biometric Login" else "Enable Biometric Login"
            textSize = 14f
            setPadding(32, 24, 32, 24)
            setOnClickListener {
                if (isBiometricEnabled()) {
                    setBiometricEnabled(false)
                    showToast("Biometric login disabled")
                } else {
                    if (isBiometricAvailable()) {
                        setBiometricEnabled(true)
                        showToast("Biometric login enabled")
                    } else {
                        showToast("Biometric not available on this device")
                    }
                }
                showHomeScreen() // Refresh
            }
        }

        val logoutButton = Button(this).apply {
            text = "Logout"
            textSize = 16f
            setPadding(32, 24, 32, 24)
            setOnClickListener {
                setAuthenticated(false)
                showToast("Logged out successfully")
                if (isBiometricAvailable() && isBiometricEnabled()) {
                    setupBiometricPrompt()
                    showBiometricPrompt()
                } else {
                    showLoginScreen()
                }
            }
        }

        val spacer = { height: Int ->
            android.view.View(this).apply {
                layoutParams = LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT, height
                )
            }
        }

        layout.addView(welcomeText)
        layout.addView(statusText)
        layout.addView(biometricStatusText)

        if (isBiometricAvailable()) {
            layout.addView(toggleBiometricButton)
            layout.addView(spacer(24))
        }

        layout.addView(logoutButton)

        setContentView(layout)
    }

    private fun showToast(message: String) {
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
    }
}